// Timing Guards: Monat/Quartal bestimmen
const today = new Date();
const isFirstWeekOfMonth = today.getDate() <= 7;
const isFirstWeekOfQuarter = isFirstWeekOfMonth && [0,3,6,9].includes(today.getMonth());
const year = today.getFullYear();
const month = today.getMonth() + 1;
const kw = Math.ceil((((today - new Date(year,0,1)) / 86400000) + new Date(year,0,1).getDay() + 1) / 7);
const scanDate = today.toISOString().split('T')[0];

return [{ json: {
  scan_date: scanDate,
  year,
  month,
  kw,
  run_monthly_updates: isFirstWeekOfMonth,
  run_quarterly_valuation: isFirstWeekOfQuarter,
  run_quarterly_col: isFirstWeekOfQuarter
}}];

// Prepare country list + always include Germany as reference
const timing = $('Timing Guards').first().json;
const countriesRaw = $('Supabase: Target Countries laden').first().json;
const countries = Array.isArray(countriesRaw) ? countriesRaw : (countriesRaw && countriesRaw.id ? [countriesRaw] : []);

// Always add Germany as reference
const hasGermany = countries.some(c => c.country_code === 'GM');
const allCountries = hasGermany ? countries : [...countries, {
  country_code: 'GM', country_name: 'Deutschland', iso_code: 'DE',
  acled_name: 'Germany', role: 'aktuell', priority: 1, status: 'active'
}];

const hasActiveCountries = countries.length > 0;

return [{ json: {
  ...timing,
  countries: allCountries,
  country_codes_fips: allCountries.map(c => c.country_code),
  country_names_acled: allCountries.filter(c => c.acled_name).map(c => c.acled_name),
  has_active_countries: hasActiveCountries
}}];

// A1: GDELT Stability via v2 DOC API (TimelineTone + TimelineVol)
// Replaces broken v1 dash_stabilitytimeline (404 since 2026)
const ctx = $('Länderliste vorbereiten').first().json;
const results = [];

for (const code of ctx.country_codes_fips) {
  if (!/^[A-Z]{2}$/.test(code)) {
    results.push({ country_code: code, error: 'Invalid FIPS code', instability_current: null });
    continue;
  }

  try {
    // GDELT v2 DOC API: TimelineTone (avg tone over time)
    const toneUrl = `https://api.gdeltproject.org/api/v2/doc/doc?query=sourcecountry:${code}&mode=TimelineTone&TIMESPAN=60d&OUTPUT=csv`;
    const toneResp = await fetch(toneUrl, { signal: AbortSignal.timeout(15000) });
    const toneCsv = await toneResp.text();

    // GDELT v2 DOC API: TimelineVol (article volume over time)
    const volUrl = `https://api.gdeltproject.org/api/v2/doc/doc?query=sourcecountry:${code}&mode=TimelineVol&TIMESPAN=60d&OUTPUT=csv`;
    const volResp = await fetch(volUrl, { signal: AbortSignal.timeout(15000) });
    const volCsv = await volResp.text();

    const parseCSV = (csv) => {
      const lines = csv.trim().split('\n').filter(l => l.trim());
      if (lines.length < 2) return { current: null, previous: null };
      const vals = lines.slice(1).map(l => {
        const parts = l.split(',');
        return { date: parts[0], value: parseFloat(parts[1]) };
      }).filter(v => !isNaN(v.value));
      if (vals.length === 0) return { current: null, previous: null };
      const mid = Math.floor(vals.length / 2);
      const recent = vals.slice(mid);
      const earlier = vals.slice(0, mid);
      const avgRecent = recent.reduce((s, v) => s + v.value, 0) / recent.length;
      const avgEarlier = earlier.length > 0 ? earlier.reduce((s, v) => s + v.value, 0) / earlier.length : avgRecent;
      return { current: avgRecent, previous: avgEarlier };
    };

    const tone = parseCSV(toneCsv);
    const vol = parseCSV(volCsv);

    // Negative tone = instability proxy. Volume spike = attention proxy.
    const toneTrend = tone.previous !== 0 ? ((tone.current - tone.previous) / Math.abs(tone.previous) * 100) : 0;
    const volTrend = vol.previous > 0 ? ((vol.current - vol.previous) / vol.previous * 100) : 0;

    // Instability score: lower tone + higher volume = more unstable
    const instability = tone.current !== null ? Math.max(0, -tone.current * 10 + Math.max(0, volTrend) * 0.5) : null;
    const prevInstability = tone.previous !== null ? Math.max(0, -tone.previous * 10 + 0) : instability;
    const instTrend = prevInstability > 0 ? ((instability - prevInstability) / prevInstability * 100) : 0;

    let alarm = 'green';
    if (instTrend > 50 || toneTrend < -50) alarm = 'red';
    else if (instTrend > 20 || toneTrend < -30 || volTrend > 100) alarm = 'yellow';

    results.push({
      country_code: code,
      instability_current: Math.round((instability || 0) * 100) / 100,
      instability_previous: Math.round((prevInstability || 0) * 100) / 100,
      instability_trend: Math.round(instTrend * 100) / 100,
      tone_current: Math.round((tone.current || 0) * 100) / 100,
      tone_previous: Math.round((tone.previous || 0) * 100) / 100,
      tone_trend: Math.round(toneTrend * 100) / 100,
      volume_trend: Math.round(volTrend * 100) / 100,
      alarm,
      source: 'gdelt_v2_doc'
    });
  } catch (e) {
    results.push({ country_code: code, error: e.message, alarm: 'yellow' });
  }
}

return [{ json: { gdelt_stability: results } }];

// A2: GDELT News Volume - Spike Detection per country
const ctx = $('Länderliste vorbereiten').first().json;
const results = [];

for (const code of ctx.country_codes_fips) {
  if (!/^[A-Z]{2}$/.test(code)) continue;
  try {
    const url = `https://api.gdeltproject.org/api/v2/doc/doc?query=sourcecountry:${code}&mode=TimelineVol&TIMESPAN=30d&OUTPUT=csv`;
    const resp = await fetch(url, { signal: AbortSignal.timeout(15000) });
    const csv = await resp.text();
    const lines = csv.trim().split('\n').filter(l => l.trim());
    if (lines.length < 3) {
      results.push({ country_code: code, spike_detected: false, spike_date: null, spike_magnitude: 0 });
      continue;
    }
    const vals = lines.slice(1).map(l => {
      const parts = l.split(',');
      return { date: parts[0], volume: parseFloat(parts[1]) || 0 };
    });
    const mean = vals.reduce((s, v) => s + v.volume, 0) / vals.length;
    const stdDev = Math.sqrt(vals.reduce((s, v) => s + Math.pow(v.volume - mean, 2), 0) / vals.length);
    const spikes = vals.filter(v => stdDev > 0 && (v.volume - mean) / stdDev > 2);
    const biggestSpike = spikes.sort((a, b) => b.volume - a.volume)[0];

    results.push({
      country_code: code,
      spike_detected: spikes.length > 0,
      spike_date: biggestSpike ? biggestSpike.date : null,
      spike_magnitude: biggestSpike ? Math.round((biggestSpike.volume - mean) / stdDev * 100) / 100 : 0
    });
  } catch (e) {
    results.push({ country_code: code, spike_detected: false, error: e.message });
  }
}

return [{ json: { gdelt_news: results } }];

// A3: ACLED Conflict Data per country (OAuth2 Token Flow)
const ctx = $('Länderliste vorbereiten').first().json;
const results = [];

// Check if ACLED credentials are configured
const acledEmail = $env.ACLED_EMAIL || '';
const acledPassword = $env.ACLED_PASSWORD || '';

if (!acledEmail || !acledPassword) {
  return [{ json: { acled: [{ error: 'ACLED credentials not configured (ACLED_EMAIL/ACLED_PASSWORD missing)', skipped: true }] } }];
}

try {
  // Step 1: Get OAuth2 token
  const tokenResp = await fetch('https://acleddata.com/oauth/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `username=${encodeURIComponent(acledEmail)}&password=${encodeURIComponent(acledPassword)}&grant_type=password&client_id=acled`,
    signal: AbortSignal.timeout(15000)
  });
  const tokenData = await tokenResp.json();
  if (!tokenData.access_token) {
    return [{ json: { acled: [{ error: 'ACLED OAuth2 failed: ' + JSON.stringify(tokenData), skipped: true }] } }];
  }

  const token = tokenData.access_token;
  const endDate = new Date().toISOString().split('T')[0];
  const startDate = new Date(Date.now() - 30 * 86400000).toISOString().split('T')[0];
  const prevStartDate = new Date(Date.now() - 60 * 86400000).toISOString().split('T')[0];

  // Step 2: Fetch data per country
  for (const country of ctx.countries) {
    const acledName = country.acled_name;
    if (!acledName) {
      results.push({ country_code: country.country_code, skipped: true, reason: 'no acled_name' });
      continue;
    }
    try {
      // Current month
      const resp = await fetch(
        `https://acleddata.com/api/acled/read?event_date=${startDate}|${endDate}&event_date_where=BETWEEN&country=${encodeURIComponent(acledName)}&limit=500`,
        { headers: { Authorization: `Bearer ${token}` }, signal: AbortSignal.timeout(15000) }
      );
      const data = await resp.json();
      const events = data.data || [];

      // Previous month
      const prevResp = await fetch(
        `https://acleddata.com/api/acled/read?event_date=${prevStartDate}|${startDate}&event_date_where=BETWEEN&country=${encodeURIComponent(acledName)}&limit=500`,
        { headers: { Authorization: `Bearer ${token}` }, signal: AbortSignal.timeout(15000) }
      );
      const prevData = await prevResp.json();
      const prevEvents = prevData.data || [];

      const count = (arr, type) => arr.filter(e => e.event_type === type).length;
      const protests = count(events, 'Protests');
      const riots = count(events, 'Riots');
      const violence = count(events, 'Violence against civilians');
      const strategic = count(events, 'Strategic developments');

      let alarm = 'green';
      if (riots > 0 || violence > 0) alarm = 'red';
      else if (protests > 5) alarm = 'yellow';

      results.push({
        country_code: country.country_code,
        country_name: acledName,
        total_events: events.length,
        protests, riots, violence, strategic_developments: strategic,
        prev_total: prevEvents.length,
        trend_vs_previous: events.length - prevEvents.length,
        alarm
      });
    } catch (e) {
      results.push({ country_code: country.country_code, error: e.message });
    }
  }
} catch (e) {
  return [{ json: { acled: [{ error: 'ACLED token fetch failed: ' + e.message }] } }];
}

return [{ json: { acled: results } }];

// A4: Polymarket Geopolitical Prediction Markets (mit Datum-Filter)
try {
  const resp = await fetch('https://gamma-api.polymarket.com/markets?tag=geopolitics&active=true&limit=100', {
    signal: AbortSignal.timeout(15000)
  });
  const markets = await resp.json();
  const ctx = $('Länderliste vorbereiten').first().json;
  const countryNames = ctx.countries.map(c => c.country_name.toLowerCase());
  const keywords = [...countryNames, 'eu', 'europe', 'germany', 'uae', 'war', 'conflict', 'sanctions', 'tax', 'regulation'];

  // Datum-Filter: nur Markets die noch nicht abgelaufen sind (Learning #6-2)
  const now = new Date();
  const sixMonthsAgo = new Date(now.getTime() - 180 * 86400000);

  const relevant = (Array.isArray(markets) ? markets : []).filter(m => {
    // Filter out old/expired markets
    if (m.endDate) {
      const endDate = new Date(m.endDate);
      if (endDate < now) return false; // already ended
    }
    if (m.createdAt) {
      const createdAt = new Date(m.createdAt);
      if (createdAt < sixMonthsAgo && !m.endDate) return false; // old without end date
    }
    const title = (m.question || m.title || '').toLowerCase();
    return keywords.some(kw => title.includes(kw));
  }).map(m => ({
    title: m.question || m.title,
    probability: m.outcomePrices ? parseFloat(JSON.parse(m.outcomePrices)[0]) : null,
    volume: m.volume || 0,
    end_date: m.endDate || null,
    created_at: m.createdAt || null
  })).sort((a, b) => (b.volume || 0) - (a.volume || 0)).slice(0, 20);

  return [{ json: { polymarket: relevant } }];
} catch (e) {
  return [{ json: { polymarket: [], error: e.message } }];
}

// A5: Immobilien Equity Update (nur 1. Woche des Monats)
const ctx = $('Länderliste vorbereiten').first().json;
if (!ctx.run_monthly_updates) {
  return [{ json: { properties_update: [], skipped: true, reason: 'Not first week of month' } }];
}

// Load properties from Supabase
try {
  const resp = await fetch(
    `${$env.SUPABASE_URL}/rest/v1/properties?status=eq.active&select=*`,
    {
      headers: {
        'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
        'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
      },
      signal: AbortSignal.timeout(15000)
    }
  );
  const properties = await resp.json();
  if (!Array.isArray(properties) || properties.length === 0) {
    return [{ json: { properties_update: [], skipped: true, reason: 'No active properties' } }];
  }

  const results = [];
  const alerts = [];

  for (const prop of properties) {
    // a) Restschuld update (Annuitätenlogik)
    const loanCurrent = parseFloat(prop.loan_amount_current) || 0;
    const loanRate = parseFloat(prop.loan_rate) || 0; // as percentage e.g. 1.8
    const monthlyPayment = parseFloat(prop.loan_monthly_payment) || 0;

    let newLoanCurrent = loanCurrent;
    let monatlicher_zins = 0;
    let monatliche_tilgung = 0;

    if (loanCurrent > 0 && monthlyPayment > 0) {
      monatlicher_zins = loanCurrent * (loanRate / 100) / 12;
      monatliche_tilgung = monthlyPayment - monatlicher_zins;
      newLoanCurrent = loanCurrent - monatliche_tilgung;
    }

    // c) Equity
    const currentValue = parseFloat(prop.current_value) || 0;
    const equity = currentValue - newLoanCurrent;

    // d) Cashflow
    const rentGross = parseFloat(prop.monthly_rent_gross) || 0;
    const hausgeld = parseFloat(prop.monthly_hausgeld) || 0;
    const nichtUmlagefaehig = parseFloat(prop.monthly_nicht_umlagefaehig) || 0;
    const verwaltung = parseFloat(prop.monthly_verwaltung) || 0;

    const cashflow_vor_steuer = rentGross - hausgeld - nichtUmlagefaehig - verwaltung - monatlicher_zins;
    const cashflow_nach_tilgung = cashflow_vor_steuer - monatliche_tilgung;
    const vermoegenszuwachs = monatliche_tilgung + cashflow_vor_steuer;

    // Update Supabase
    if (loanCurrent > 0 && monthlyPayment > 0) {
      await fetch(
        `${$env.SUPABASE_URL}/rest/v1/properties?id=eq.${prop.id}`,
        {
          method: 'PATCH',
          headers: {
            'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
            'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
            'Content-Type': 'application/json',
            'Prefer': 'return=minimal'
          },
          body: JSON.stringify({ loan_amount_current: Math.round(newLoanCurrent * 100) / 100 }),
          signal: AbortSignal.timeout(10000)
        }
      );
    }

    // e) Zinsbindung alert
    if (prop.loan_zinsbindung_end) {
      const zinsEnd = new Date(prop.loan_zinsbindung_end);
      const monthsLeft = (zinsEnd - new Date()) / (30 * 86400000);
      if (monthsLeft < 24 && monthsLeft > 0) {
        alerts.push({
          type: 'zinsbindung',
          message: `⚠️ Zinsbindung für ${prop.name} läuft am ${prop.loan_zinsbindung_end} aus (${Math.round(monthsLeft)} Monate). Anschlussfinanzierung verhandeln!`,
          urgency: 'yellow'
        });
      }
    }

    results.push({
      id: prop.id,
      name: prop.name,
      loan_old: loanCurrent,
      loan_new: Math.round(newLoanCurrent * 100) / 100,
      tilgung: Math.round(monatliche_tilgung * 100) / 100,
      zins: Math.round(monatlicher_zins * 100) / 100,
      equity: Math.round(equity * 100) / 100,
      cashflow_vor_steuer: Math.round(cashflow_vor_steuer * 100) / 100,
      cashflow_nach_tilgung: Math.round(cashflow_nach_tilgung * 100) / 100,
      vermoegenszuwachs: Math.round(vermoegenszuwachs * 100) / 100
    });
  }

  return [{ json: { properties_update: results, alerts } }];
} catch (e) {
  return [{ json: { properties_update: [], error: e.message } }];
}

// A6: Kurs-Update (Yahoo Finance + Twelvedata Fallback + CoinGecko)
const results = { stocks: [], crypto: [], alerts: [] };

try {
  // Load portfolio holdings
  const resp = await fetch(
    `${$env.SUPABASE_URL}/rest/v1/portfolio_holdings?select=*`,
    {
      headers: {
        'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
        'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
      },
      signal: AbortSignal.timeout(10000)
    }
  );
  const holdings = await resp.json();
  if (!Array.isArray(holdings) || holdings.length === 0) {
    return [{ json: { kurs_update: results, skipped: true, reason: 'No holdings' } }];
  }

  const stockHoldings = holdings.filter(h => h.ticker && h.type !== 'Krypto' && h.type !== 'Edelmetall');
  const cryptoHoldings = holdings.filter(h => h.type === 'Krypto');

  // Stock/ETF prices via Yahoo Finance with Twelvedata fallback
  for (const h of stockHoldings) {
    let price = null;
    let source = null;
    try {
      // Yahoo Finance primary
      const yahooUrl = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(h.ticker)}?interval=1d&range=5d`;
      const yahooResp = await fetch(yahooUrl, { signal: AbortSignal.timeout(10000) });
      if (yahooResp.ok) {
        const yahooData = await yahooResp.json();
        const closes = yahooData?.chart?.result?.[0]?.indicators?.quote?.[0]?.close || [];
        const validCloses = closes.filter(c => c !== null);
        if (validCloses.length > 0) {
          price = validCloses[validCloses.length - 1];
          source = 'yahoo';
        }
      }
    } catch (e) { /* Yahoo failed, try fallback */ }

    // Twelvedata fallback
    if (price === null && $env.TWELVEDATA_API_KEY) {
      try {
        const tdUrl = `https://api.twelvedata.com/price?symbol=${encodeURIComponent(h.ticker)}&apikey=${$env.TWELVEDATA_API_KEY}`;
        const tdResp = await fetch(tdUrl, { signal: AbortSignal.timeout(10000) });
        const tdData = await tdResp.json();
        if (tdData.price) {
          price = parseFloat(tdData.price);
          source = 'twelvedata';
        }
      } catch (e) { /* Twelvedata also failed */ }
    }

    if (price !== null) {
      // Update Supabase
      await fetch(
        `${$env.SUPABASE_URL}/rest/v1/portfolio_holdings?id=eq.${h.id}`,
        {
          method: 'PATCH',
          headers: {
            'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
            'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
            'Content-Type': 'application/json',
            'Prefer': 'return=minimal'
          },
          body: JSON.stringify({
            current_price: Math.round(price * 100) / 100,
            last_price_update: new Date().toISOString().split('T')[0]
          }),
          signal: AbortSignal.timeout(10000)
        }
      );
      results.stocks.push({ ticker: h.ticker, name: h.name, price, source });
    } else {
      results.alerts.push({ message: `⚠️ Kurs für ${h.ticker} nicht abrufbar`, urgency: 'yellow' });
    }
  }

  // Crypto via CoinGecko
  if (cryptoHoldings.length > 0) {
    try {
      const ids = cryptoHoldings.map(h => (h.ticker || h.name || '').toLowerCase()).join(',');
      const cgHeaders = { 'Accept': 'application/json' };
      if ($env.COINGECKO_API_KEY) {
        cgHeaders['x-cg-demo-api-key'] = $env.COINGECKO_API_KEY;
      }
      const cgResp = await fetch(
        `https://api.coingecko.com/api/v3/simple/price?ids=${ids}&vs_currencies=eur`,
        { headers: cgHeaders, signal: AbortSignal.timeout(10000) }
      );
      const cgData = await cgResp.json();
      for (const h of cryptoHoldings) {
        const key = (h.ticker || h.name || '').toLowerCase();
        if (cgData[key] && cgData[key].eur) {
          const price = cgData[key].eur;
          await fetch(
            `${$env.SUPABASE_URL}/rest/v1/portfolio_holdings?id=eq.${h.id}`,
            {
              method: 'PATCH',
              headers: {
                'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
                'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
                'Content-Type': 'application/json',
                'Prefer': 'return=minimal'
              },
              body: JSON.stringify({ current_price: price, last_price_update: new Date().toISOString().split('T')[0] }),
              signal: AbortSignal.timeout(10000)
            }
          );
          results.crypto.push({ id: key, name: h.name, price, source: 'coingecko' });
        }
      }
    } catch (e) {
      results.alerts.push({ message: '⚠️ CoinGecko API nicht erreichbar', urgency: 'yellow' });
    }
  }

  // Check Haltefristen in portfolio_lots
  try {
    const lotsResp = await fetch(
      `${$env.SUPABASE_URL}/rest/v1/portfolio_lots?status=eq.held&select=*,portfolio_holdings(name,ticker)`,
      {
        headers: {
          'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
          'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
        },
        signal: AbortSignal.timeout(10000)
      }
    );
    const lots = await lotsResp.json();
    if (Array.isArray(lots)) {
      const now = new Date();
      for (const lot of lots) {
        if (lot.tax_free_after) {
          const tfDate = new Date(lot.tax_free_after);
          if (tfDate <= now) {
            results.alerts.push({
              message: `✅ Position ${lot.portfolio_holdings?.name || 'Unbekannt'} (Lot ${lot.purchase_date}) ist jetzt steuerfrei!`,
              urgency: 'green'
            });
          } else if (tfDate <= new Date(now.getTime() + 30 * 86400000)) {
            results.alerts.push({
              message: `⚠️ Position ${lot.portfolio_holdings?.name || 'Unbekannt'} wird in ${Math.ceil((tfDate - now) / 86400000)} Tagen steuerfrei`,
              urgency: 'yellow'
            });
          }
        }
      }
    }
  } catch (e) { /* lots check failed, not critical */ }

} catch (e) {
  return [{ json: { kurs_update: results, error: e.message } }];
}

return [{ json: { kurs_update: results } }];

// A7: Wechselkurs-Update (ExchangeRate-API)
const ctx = $('Länderliste vorbereiten').first().json;
try {
  const resp = await fetch('https://open.er-api.com/v6/latest/EUR', { signal: AbortSignal.timeout(10000) });
  const data = await resp.json();
  if (data.result !== 'success') {
    return [{ json: { fx_rates: [], error: 'ExchangeRate API error' } }];
  }

  const rates = data.rates;
  // Get currencies for target countries + USD + CHF
  const targetCurrencies = ['USD', 'CHF'];
  // Map known country currencies
  const currencyMap = { 'AE': 'AED', 'CY': 'EUR', 'PO': 'EUR', 'MT': 'EUR', 'SN': 'SGD', 'GM': 'EUR', 'GG': 'GEL', 'PA': 'PYG', 'UK': 'GBP' };
  for (const c of ctx.countries) {
    const cur = currencyMap[c.country_code];
    if (cur && !targetCurrencies.includes(cur) && cur !== 'EUR') {
      targetCurrencies.push(cur);
    }
  }

  const scanDate = ctx.scan_date;
  const results = [];
  const alerts = [];

  // Load previous rates for trend
  const prevResp = await fetch(
    `${$env.SUPABASE_URL}/rest/v1/fx_rates?order=scan_date.desc&limit=${targetCurrencies.length}&scan_date=neq.${scanDate}`,
    {
      headers: {
        'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
