const fetchECB = async (seriesId) => {
  try {
    const url = `https://data-api.ecb.europa.eu/service/data/FM/${seriesId}?format=jsondata&lastNObservations=10`;
    const resp = await fetch(url, { signal: AbortSignal.timeout(15000) });
