    const seriesKey = Object.keys(data.dataSets[0].series)[0];
    const observations = data.dataSets[0].series[seriesKey].observations;
    const sortedKeys = Object.keys(observations).sort();
    if (sortedKeys.length < 2) return { current: null, previous: null, changed: false };
    const lastKey = sortedKeys[sortedKeys.length - 1];
    const prevKey = sortedKeys[sortedKeys.length - 2];
    const currentRate = observations[lastKey][0];
    const prevRate = observations[prevKey][0];
    return { current: currentRate, previous: prevRate, changed: currentRate !== prevRate, changeBp: Math.round((currentRate - prevRate) * 100) };
  } catch (e) {
    return { current: null, error: e.message };
  }
};

