  body: JSON.stringify({ scan_date: ctx.scan_date, ...gold.gold, ...ecb.ecb }),
  signal: AbortSignal.timeout(10000)
});

// Save monthly_scan_results
const scanResult = {
  scan_date: ctx.scan_date,
  raw_data: { gdelt: gdeltStab, gdelt_news: gdeltNews, acled, polymarket, immobilien, kurse, fx, inflation, gold, ecb, marketIntel, fristen, webSearch },
  alerts: allAlerts,
  changes_detected: allAlerts.some(a => a.urgency === 'red'),
  countries_scanned: ctx.country_codes_fips,
  cost_eur: 0.10 // estimated Tavily cost
};
await fetch(`${$env.SUPABASE_URL}/rest/v1/monthly_scan_results`, {
  method: 'POST',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: JSON.stringify(scanResult),
  signal: AbortSignal.timeout(10000)
});

return [{ json: {
  scan_date: ctx.scan_date,
  kw: ctx.kw,
  countries_scanned: ctx.country_codes_fips,
  total_alerts: allAlerts.length,
  red_alerts: allAlerts.filter(a => a.urgency === 'red').length,
  yellow_alerts: allAlerts.filter(a => a.urgency === 'yellow').length,
  all_alerts: allAlerts,
  has_osint_alarms: hasOsintAlarms,
  has_relevant_search: hasRelevantSearchResults,
  raw_data_summary: {
    gdelt_countries: gdeltStab.gdelt_stability?.length || 0,
    acled_countries: acled.acled?.length || 0,
    polymarket_markets: polymarket.polymarket?.length || 0,
    fx_currencies: fx.fx_rates?.length || 0,
    gold_price: gold.gold?.gold_price_eur || null,
    ecb_deposit: ecb.ecb?.ecb_deposit_rate || null,
    web_search_results: Object.values(webSearch.web_search || {}).flat().length,
    fristen_count: fristen.fristen?.length || 0
  }
}}];

// C1: OSINT Anomalie-Bewertung (Haiku - nur bei Alarm)
const ctx = $input.first().json;
const alarmedData = ctx.all_alerts.filter(a => ['gdelt', 'gdelt_news', 'acled'].includes(a.source));

if (alarmedData.length === 0) {
  return [{ json: { c1_assessment: null, skipped: true } }];
}

const prompt = `Analysiere die folgenden Instabilitäts- und Konfliktdaten für die Zielländer des Mandanten. Gibt es besorgniserregende Trends? Kontext: Der Mandant plant mittelfristig die Verlagerung seines Lebensmittelpunkts in eines dieser Länder.\n\nAlarme:\n${alarmedData.map(a => a.message).join('\n')}\n\nAntworte auf Deutsch in JSON: {"assessment": "...", "urgency": "high|medium|low", "affected_countries": [...], "recommendation": "..."}`;

try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: $env.MODEL_HAIKU || 'claude-haiku-4-5-20251001',
      max_tokens: 500,
      messages: [{ role: 'user', content: prompt }]
    }),
    signal: AbortSignal.timeout(30000)
  });
  const data = await resp.json();
  const text = data.content?.[0]?.text || '';
  let parsed;
  try { parsed = JSON.parse(text); } catch { parsed = { assessment: text, urgency: 'medium' }; }
  return [{ json: { c1_assessment: parsed, tokens_in: data.usage?.input_tokens || 0, tokens_out: data.usage?.output_tokens || 0 } }];
} catch (e) {
  return [{ json: { c1_assessment: null, error: e.message } }];
}

// C2: Rechtsänderungs-Bewertung (Haiku - nur wenn relevante Treffer)
const agg = $('Ergebnisse aggregieren').first().json;
const hasSearch = agg.has_relevant_search;

if (!hasSearch) {
  return [{ json: { c2_assessment: null, skipped: true } }];
}

// Get web search results from scan_results
const scanResp = await fetch(
  `${$env.SUPABASE_URL}/rest/v1/monthly_scan_results?scan_date=eq.${agg.scan_date}&order=created_at.desc&limit=1`,
  {
    headers: {
      'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
    },
    signal: AbortSignal.timeout(10000)
  }
);
const scanData = await scanResp.json();
const rawData = Array.isArray(scanData) && scanData[0] ? scanData[0].raw_data : {};
const webSearch = rawData.webSearch?.web_search || {};

const searchSummary = Object.entries(webSearch).map(([cat, results]) => {
  if (!Array.isArray(results) || results.length === 0) return '';
  return `${cat}:\n${results.map(r => `- ${r.title}: ${r.snippet}`).join('\n')}`;
}).filter(s => s).join('\n\n');

if (!searchSummary) {
  return [{ json: { c2_assessment: null, skipped: true } }];
}

const prompt = `Gibt es relevante Rechtsänderungen für einen Mandanten der: aus DE wegziehen will, Immobilien in DE hält, eine zweite Staatsbürgerschaft anstrebt?\n\nSuchergebnisse:\n${searchSummary.substring(0, 2000)}\n\nAntworte auf Deutsch in JSON: {"changes_detected": true/false, "summary": "...", "affected_agents": [...], "urgency": "high|medium|low"}`;

try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: $env.MODEL_HAIKU || 'claude-haiku-4-5-20251001',
      max_tokens: 500,
      messages: [{ role: 'user', content: prompt }]
    }),
    signal: AbortSignal.timeout(30000)
  });
  const data = await resp.json();
  const text = data.content?.[0]?.text || '';
  let parsed;
  try { parsed = JSON.parse(text); } catch { parsed = { changes_detected: false, summary: text }; }
  return [{ json: { c2_assessment: parsed, tokens_in: data.usage?.input_tokens || 0, tokens_out: data.usage?.output_tokens || 0 } }];
} catch (e) {
  return [{ json: { c2_assessment: null, error: e.message } }];
}

// Telegram Delivery: Compose and send scan summary
const agg = $('Ergebnisse aggregieren').first().json;

// Get C1 and C2 assessments
let c1 = null;
try { c1 = $('C1: OSINT Bewertung (Haiku)').first().json.c1_assessment; } catch {}
try { if (!c1) c1 = $('C1: Kein Alarm').first().json.c1_assessment; } catch {}

let c2 = null;
try { c2 = $('C2: Rechtsänderung (Haiku)').first().json.c2_assessment; } catch {}

let message;
if (agg.red_alerts === 0 && agg.yellow_alerts <= 2) {
  // All clear
  message = `🟢 *Weekly Scan KW${agg.kw}*\n\nKeine relevanten Änderungen.`;
  if (agg.raw_data_summary.gold_price) {
    message += `\n\n💰 Gold: ${agg.raw_data_summary.gold_price}€`;
  }
  if (agg.raw_data_summary.ecb_deposit) {
    message += `\n🏦 EZB: ${agg.raw_data_summary.ecb_deposit}%`;
  }
  message += `\n\n${agg.raw_data_summary.gdelt_countries} Länder gescannt, ${agg.raw_data_summary.web_search_results} Web-Treffer.\n📊 Details im Dashboard`;
} else {
  // Alerts present
  message = `⚠️ *Weekly Scan KW${agg.kw}*\n\n`;
  message += `${agg.red_alerts} 🔴 | ${agg.yellow_alerts} 🟡\n\n`;

  // Top 5 alerts
  const topAlerts = agg.all_alerts
    .sort((a, b) => (a.urgency === 'red' ? 0 : 1) - (b.urgency === 'red' ? 0 : 1))
    .slice(0, 5);
  for (const a of topAlerts) {
    message += `${a.message}\n`;
  }

  if (c1 && c1.assessment) {
    message += `\n*OSINT:* ${c1.assessment.substring(0, 200)}`;
  }
  if (c2 && c2.changes_detected) {
    message += `\n*Recht:* ${c2.summary?.substring(0, 200) || 'Änderungen erkannt'}`;
  }

  message += `\n\n📊 Vollständiger Brief im Dashboard`;
}

// Truncate to Telegram limit
if (message.length > 4000) message = message.substring(0, 3997) + '...';

return [{ json: { message, urgency: agg.red_alerts > 0 ? 'red' : (agg.yellow_alerts > 0 ? 'yellow' : 'green'), category: 'weekly_scan' } }];

// Prepare logger input
const agg = $('Ergebnisse aggregieren').first().json;
return [{ json: {
  session_id: `weekly_scan_${agg.scan_date}`,
  agent_name: 'weekly_scan',
  model: 'none',
  input_summary: `Weekly Scan KW${agg.kw}: ${agg.countries_scanned?.length || 0} Länder`,
  output_summary: `${agg.total_alerts} Alerts (${agg.red_alerts}🔴 ${agg.yellow_alerts}🟡), ${agg.raw_data_summary.web_search_results} Web-Treffer`,
  tokens_in: 0,
  tokens_out: 0,
  cost_eur: 0.10
}}];
